namespace UnitTests
{
    public class SqliteNodaTimeEfCore10Test
    {
        [Fact]
        public void GetNeededPackages_Sqlite_WithNodaTime_EfCore10()
        {
            // Act
            var packages = Providers.GetNeededPackages(
                DatabaseType.SQLite,
                useSpatial: false,
                useNodaTime: true,
                useDateOnlyTimeOnly: false,
                useHierarchyId: false,
                discoverMultipleResultSets: false,
                hasProcedures: false,
                CodeGenerationMode.EFCore10);

            // Assert
            Assert.NotNull(packages);
            Assert.Equal(2, packages.Count); // main Sqlite package + NodaTime package

            var mainPackage = packages.First(p => p.IsMainProviderPackage);
            Assert.Equal("Microsoft.EntityFrameworkCore.Sqlite", mainPackage.PackageId);
            Assert.Equal("10.0.6", mainPackage.Version);
            Assert.Equal("Sqlite", mainPackage.UseMethodName);

            var nodaTimePackage = packages.First(p => !p.IsMainProviderPackage);
            Assert.Equal("EntityFrameworkCore.Sqlite.NodaTime", nodaTimePackage.PackageId);
            Assert.Equal("10.0.0", nodaTimePackage.Version);
            Assert.Equal("NodaTime", nodaTimePackage.UseMethodName);
            Assert.Contains(DatabaseType.SQLite, nodaTimePackage.DatabaseTypes);
        }

        [Fact]
        public void GetNeededPackages_Sqlite_WithoutNodaTime_EfCore10()
        {
            // Act
            var packages = Providers.GetNeededPackages(
                DatabaseType.SQLite,
                useSpatial: false,
                useNodaTime: false,
                useDateOnlyTimeOnly: false,
                useHierarchyId: false,
                discoverMultipleResultSets: false,
                hasProcedures: false,
                CodeGenerationMode.EFCore10);

            // Assert
            Assert.NotNull(packages);
            Assert.Single(packages); // only main Sqlite package

            var mainPackage = packages.First();
            Assert.Equal("Microsoft.EntityFrameworkCore.Sqlite", mainPackage.PackageId);
            Assert.Equal("10.0.6", mainPackage.Version);
        }
    }
}

